class Solution {
    public int numberOfSpecialChars(String word) {
        int[] lower = new int[26];
        int[] upper = new int[26];
        for (char c : word.toCharArray()) {
            if (Character.isLowerCase(c)) {
                lower[c - 'a'] = 1;
            } else {
                upper[c - 'a'] = 1;
            }
        }
        int res = 0;
        for (int i = 0; i < 26; i++) {
            if (lower[i] == 1 && upper[i] == 1) {
                int lastLowerIndex = -1;
                int firstUpperIndex = Integer.MAX_VALUE;
                for (int j = 0; j < word.length(); j++) {
                    if (word.charAt(j) == 'a' + i) {
                        if (Character.isLowerCase(word.charAt(j))) {
                            lastLowerIndex = j;
                        } else {
                            firstUpperIndex = j;
                            break;
                        }
                    }
                }
                if (lastLowerIndex < firstUpperIndex) {
                    res++;
                }
            }
        }
        return res;
    }
}
